    "questions": [
      {
        "question": "What are the primary sources of sweet flavors in Thai cuisine?",
        "options": [
          "Coconut milk and fish sauce",
          "Palm sugar and fruits",
          "Chili peppers and herbs",
          "Vinegar and lime juice"
        ],
        "correctAnswer": 1,
        "explanation": "Palm sugar and fruits are the primary sources of sweet flavors in Thai cuisine."
      },
      {
        "question": "Which ingredient typically adds sourness to Thai dishes?",
        "options": [
          "Fish sauce",
          "Palm sugar",
          "Lime juice",
          "Coconut milk"
        ],
        "correctAnswer": 2,
        "explanation": "Lime juice is commonly used to add sourness to Thai dishes."
      },
      {
        "question": "What is the balance of flavors that defines Thai cuisine?",
        "options": [
          "Sweet, sour, salty, and spicy",
          "Sweet, bitter, salty, and umami",
          "Sour, sweet, savory, and bland",
          "Salty, sweet, spicy, and tangy"
        ],
        "correctAnswer": 0,
        "explanation": "Thai cuisine is defined by the balance of sweet, sour, salty, and spicy flavors."
      },
      {
        "question": "Why is sweetness essential in Thai dishes?",
        "options": [
          "To mask bitterness",
          "To create harmony in dishes",
          "To enhance spiciness",
          "To increase shelf life"
        ],
        "correctAnswer": 1,
        "explanation": "Sweetness is essential for creating harmony in Thai dishes."
      }
    ]
  }
